		}
		sb.WriteString("  </changed-files>\n\n")
		sections = append(sections, evidence.EvidenceAssemblySection{
			Name:          "changed-files",
			BytesIncluded: sb.Len() - invStart,
			SelectedItems: paths,
		})
	}

